sys_client_script.script:
function onLoad() {
    // Show welcome info message when the incident form loads
    var msg = 'Welcome to Incident Enhancement! Let\'s gear up for a ride....!';

    try {
        // Use ServiceNow's info message instead of alert for better UX
        g_form.addInfoMessage(msg);

        // Alternative: Use GlideModal for a more polished welcome
        /*
        var modal = new GlideModal('glide_alert_standard', false, 500);
        modal.setTitle('Welcome!');
        modal.setBody(msg);
        modal.render();
        */

    } catch (e) {
        // Fallback to standard alert if info message fails
        alert(msg);
    }
}
